

export const conhComple = [
    
    { id:10, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Especialista", enunciado:"De acordo com a Lei nº 8.429/1992 (redação atualizada), constitui ato de improbidade administrativa que atenta contra os princípios da administração pública a ação ou omissão dolosa que viole a honestidade.", imagem:null, alternativas:["Certo","Errado"], resposta_correta:0, explicacao:"A Lei exige agora o dolo específico para a caracterização do ato de improbidade.", status:0, historico:0 },
{ id:20, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Especialista", enunciado:"De acordo com a Lei nº 8.429/1992 (redação atualizada), constitui ato de improbidade administrativa que atenta contra os princípios da administração pública a ação ou omissão dolosa que viole a honestidade.", imagem:null, alternativas:["Certo","Errado"], resposta_correta:0, explicacao:"A Lei exige agora o dolo específico para a caracterização do ato de improbidade.", status:0, historico:0 },
{ id:28, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", banca:"Especialista", enunciado:"Na LGPD, o 'Controlador' é a pessoa física ou jurídica a quem competem as decisões referentes ao tratamento de dados pessoais.", imagem:null, alternativas:["Certo","Errado"], resposta_correta:0, explicacao:"Definição literal do Art. 5º, VI, da Lei 13.709/2018.", status:0, historico:0 },
{ id:35, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Especialista", enunciado:"No processo administrativo federal, a Administração tem o dever de emitir decisão explícita em solicitações ou reclamações em matéria de sua competência.", imagem:null, alternativas:["Certo","Errado"], resposta_correta:0, explicacao:"Dever de decidir previsto no Art. 48 da Lei 9.784/1999.", status:0, historico:0 },
{ id:284, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Acerca do conceito de ética aplicado à função pública, assinale a alternativa que melhor descreve a relação entre ética e moral sob a ótica da Administração:", imagem:null, alternativas:["A) Ética e moral são sinônimos perfeitos, tratando-se exclusivamente do cumprimento das leis vigentes.","B) A ética é a ciência do comportamento moral, sendo de natureza teórica e reflexiva, enquanto a moral é a prática de hábitos e costumes.","C) No setor público, a moral prevalece sobre a ética, pois as decisões devem ser baseadas apenas na tradição local da autarquia.","D) A conduta ética do servidor restringe-se ao ambiente de trabalho, não havendo repercussão de seus atos privados na imagem da instituição.","E) A ética administrativa exige que o servidor escolha sempre a opção mais vantajosa para si, desde que não viole a lei de forma explícita."], resposta_correta:1, explicacao:"Justificativa: A alternativa B traz a distinção clássica: Ética como campo de estudo (teoria/universal) e Moral como prática (costumes/temporal). Dica do Especialista: A Quadrix ama cobrar essa distinção acadêmica antes de entrar na parte legal.", status:0, historico:0 },
{ id:285, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"No que se refere à ética e à conduta do servidor público no exercício de suas funções, é correto afirmar que:", imagem:null, alternativas:["A) O servidor deve decidir entre o que é legal e ilegal, sendo o critério da honestidade secundário em face da conveniência administrativa.","B) A moralidade da administração pública não se limita à distinção entre o bem e o mal, exigindo que o fim seja sempre o bem comum.","C) Um ato administrativo, para ser ético, basta estar previsto em lei, independentemente da intenção do agente ou do resultado prático.","D) A cortesia e a urbanidade são deveres facultativos, aplicáveis apenas no atendimento ao público externo, mas não aos colegas de trabalho.","E) O servidor pode omitir informações de interesse público se considerar que a divulgação trará críticas à gestão do Conselho Regional."], resposta_correta:1, explicacao:"Justificativa: O 'bem comum' é o elemento finalístico obrigatório da ética administrativa. O erro da A é dizer que honestidade é secundária. Dica do Especialista: Fique atento ao termo 'Bem Comum'; para a Quadrix, ele é o norte da moralidade administrativa.", status:0, historico:0 },
{ id:286, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"O princípio constitucional da Administração Pública que veda a promoção pessoal de agentes públicos em atos, programas ou obras de órgãos públicos é o princípio da:", imagem:null, alternativas:["A) Legalidade.","B) Moralidade.","C) Publicidade.","D) Impessoalidade.","E) Eficiência."], resposta_correta:3, explicacao:"Justificativa: A impessoalidade (Art. 37, § 1º da CF) impede que a máquina pública seja usada para autopromoção. Dica do Especialista: A banca costuma confundir o candidato ligando 'promoção pessoal' ao princípio da Publicidade só porque envolve 'divulgação', mas a vedação em si é pela Impessoalidade.", status:0, historico:0 },
{ id:287, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Considere que o CRECI-BA decida contratar um serviço de reforma sem realizar licitação, fora das hipóteses legais de dispensa ou inexigibilidade. Tal ato viola frontalmente o princípio da:", imagem:null, alternativas:["A) Moralidade, exclusivamente, pois não há dano ao erário.","B) Legalidade, que impõe que a Administração só pode fazer o que a lei autoriza.","C) Eficiência, pois o processo licitatório seria mais demorado e caro.","D) Publicidade, pois a dispensa não precisa ser publicada em Diário Oficial.","E) Supremacia do interesse privado sobre o interesse público."], resposta_correta:1, explicacao:"Justificativa: Pela Legalidade Estrita, o administrador público está vinculado aos trilhos da lei. Dica do Especialista: Lembre-se da diferença: na vida privada pode-se fazer tudo que a lei não proíbe; na pública, apenas o que ela permite.", status:0, historico:0 },
{ id:288, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Sobre o Princípio da Eficiência, introduzido pela Emenda Constitucional nº 19/1998, assinale a alternativa correta:", imagem:null, alternativas:["A) Determina que o servidor deve buscar apenas a redução de custos, mesmo que a qualidade do atendimento ao corretor diminua.","B) Exige que a atividade administrativa seja exercida com presteza, perfeição e rendimento funcional.","C) Autoriza o administrador a descumprir normas legais em nome da agilidade no atendimento de demandas urgentes.","D) Refere-se apenas ao uso de novas tecnologias, não se aplicando ao comportamento individual do servidor administrativo.","E) É um princípio secundário que só deve ser observado se houver orçamento sobrando no exercício financeiro."], resposta_correta:1, explicacao:"Justificativa: Eficiência foca no binômio meio/resultado: melhor resultado com o menor custo/tempo possível. Dica do Especialista: A Quadrix adora usar a palavra 'rendimento' ou 'perfeição' para definir eficiência. Memorize essas palavras-chave.", status:0, historico:0 },
{ id:289, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Ao atuar no setor de fiscalização, um servidor percebe que um dos corretores irregulares é seu vizinho e decide não lavrar o auto de infração para manter a boa vizinhança. Sob o ponto de vista ético, este servidor:", imagem:null, alternativas:["A) Agiu corretamente, pois a harmonia social é um princípio superior à burocaacia.","B) Praticou um ato de urbanidade, que é um dever ético fundamental do servidor.","C) Comprometeu a dignidade da função pública, priorizando o interesse particular sobre o público.","D) Agiu dentro da legalidade, pois o fiscal possui discricionariedade total para decidir quem autuar.","E) Deveria ter solicitado um pagamento simbólico para regularizar a situação sem burocaacia."], resposta_correta:2, explicacao:"Justificativa: A ética pública veda o uso do cargo para favorecer amigos ou conhecidos. Isso fere a moralidade e a impessoalidade. Dica do Especialista: Casos hipotéticos envolvendo 'amizade' ou 'parentesco' são clássicos da Quadrix para testar Impessoalidade.", status:0, historico:0 },
{ id:290, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"O dever de transparência da Administração Pública, que permite o controle social dos atos administrativos, é a materialização direta do princípio da:", imagem:null, alternativas:["A) Moralidade.","B) Eficiência.","C) Publicidade.","D) Legalidade.","E) Razoabilidade."], resposta_correta:2, explicacao:"Justificativa: Publicidade é o dever de dar transparência e visibilidade aos atos, permitindo o controle pelos cidadãos. Dica do Especialista: Lembre-se que a publicidade é a regra; o sigilo é a exceção (segurança da sociedade ou estado).", status:0, historico:0 },
{ id:291, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Analise as afirmações abaixo sobre o conceito de probidade administrativa:\nI. A probidade é um desdobramento do princípio da moralidade.\nII. Atos de improbidade podem levar à suspensão dos direitos políticos.\nIII. Apenas danos financeiros (erário) configuram improbidade, não havendo improbidade em atos que apenas violam princípios.\nEstá(ão) correta(s):", imagem:null, alternativas:["A) Apenas I.","B) Apenas II.","C) Apenas I e II.","D) Apenas II e III.","E) Todas as afirmações."], resposta_correta:2, explicacao:"Justificativa: A III está errada. Atos que atentam contra os princípios (Art. 11 da Lei 8.429) também são improbidade, mesmo sem dano financeiro direto. Dica do Especialista: 'Atentar contra princípios' é uma categoria autônoma de improbidade. Cuidado!", status:0, historico:0 },
{ id:292, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Dentre os elementos que compõem o 'trabalho' do servidor público, a ética exige que ele não despreze o 'elemento ético' de sua conduta. Isso significa que:", imagem:null, alternativas:["A) Ele deve focar apenas no resultado, independentemente dos meios utilizados.","B) A legalidade do ato é suficiente para garantir que ele seja ético e moral.","C) Ele deve integrar a legalidade e a finalidade à moralidade de sua conduta para o bem comum.","D) A moralidade é um critério subjetivo que cada servidor define conforme sua consciência pessoal.","E) O elemento ético é opcional em situações de crise financeira da autarquia."], resposta_correta:2, explicacao:"Justificativa: A conduta ética é a fusão de lei, objetivo (finalidade) e moral. Dica do Especialista: A banca gosta de dizer que a moralidade 'sozinha' basta ou que a legalidade 'sozinha' basta. Ambas estão erradas; deve haver integração.", status:0, historico:0 },
{ id:293, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"O princípio que estabelece que a Administração Pública deve atuar de forma neutra, sem beneficiar ou prejudicar pessoas específicas, focando apenas no interesse coletivo, é o da:", imagem:null, alternativas:["A) Legalidade.","B) Eficiência.","C) Impessoalidade.","D) Publicidade.","E) Motivação."], resposta_correta:2, explicacao:"Justificativa: A Impessoalidade exige neutralidade e objetividade no tratamento de todos os administrados. Dica do Especialista: Neutralidade = Impessoalidade. É o termo técnico que a Quadrix costuma usar em questões de nível médio.", status:0, historico:0 },
{ id:294, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Um edital de concurso para o CRECI exige requisitos que não possuem qualquer relação com as atribuições do cargo. Essa conduta administrativa viola, primordialmente, o princípio da:", imagem:null, alternativas:["A) Moralidade.","B) Razoabilidade/Proporcionalidade.","C) Publicidade.","D) Hierarquia.","E) Continuidade do serviço público."], resposta_correta:1, explicacao:"Justificativa: Exigências absurdas ou sem nexo lógico violam a razoabilidade. Dica do Especialista: Embora não esteja no LIMPE (Art. 37), a Razoabilidade é um princípio implícito/doutrinário muito cobrado pela Quadrix em temas de concursos.", status:0, historico:0 },
{ id:295, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Quanto à conduta ética no trato com documentos e informações no Conselho Regional, assinale a alternativa correta:", imagem:null, alternativas:["A) O servidor tem o direito de reter documentos originais em sua residência para agilizar o trabalho.","B) A publicidade de atos administrativos é absoluta, não havendo qualquer hipótese de sigilo no CRECI.","C) A alteração ou deturpação do teor de documentos oficiais constitui grave infração ética e legal.","D) Informações obtidas no exercício da função podem ser compartilhadas livremente em redes sociais pessoais.","E) O servidor deve dificultar o acesso a documentos públicos para evitar críticas à gestão administrativa."], resposta_correta:2, explicacao:"Justificativa: A integridade documental é dever ético e legal (fé pública). Dica do Especialista: Questões sobre 'redes sociais' e 'vazamento de dados' estão em alta na banca devido à LGPD.", status:0, historico:0 },
{ id:296, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"A obrigação do administrador público de justificar os fundamentos de fato e de direito que o levaram a tomar determinada decisão refere-se ao princípio da:", imagem:null, alternativas:["A) Autotutela.","B) Motivação.","C) Especialidade.","D) Eficiência.","E) Legalidade."], resposta_correta:1, explicacao:"Justificativa: Motivação é a exposição das razões que justificam o ato administrativo. Dica do Especialista: Cuidado para não confundir Motivo (fato) com Motivação (exposição do fato). A banca troca esses nomes.", status:0, historico:0 },
{ id:297, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Considere que um servidor do CRECI-BA seja extremamente produtivo e rápido, mas trate os corretores de forma grosseira e desrespeitosa. Nesse caso, é correto afirmar que:", imagem:null, alternativas:["A) O servidor cumpre o princípio da eficiência, portanto sua conduta é irrepreensível.","B) A urbanidade no tratamento não é critério de avaliação ética no serviço público.","C) O servidor viola deveres éticos fundamentais, pois a cortesia é indissociável da função pública.","D) A produtividade compensa a falta de educação, sendo um comportamento aceitável em autarquias.","E) O servidor só pode ser punido se a grosseria for feita por escrito em documento oficial."], resposta_correta:2, explicacao:"Justificativa: Ética envolve o 'como' fazer, não apenas o 'quanto' fazer. Cortesia e urbanidade são deveres. Dica do Especialista: A Quadrix foca muito na ideia de que 'eficiência não justifica falta de ética'.", status:0, historico:0 },
{ id:298, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"O princípio que permite à própria Administração Pública anular seus atos quando eivados de vícios de legalidade chama-se princípio da:", imagem:null, alternativas:["A) Autotutela.","B) Supremacia do Interesse Público.","C) Contraditório.","D) Publicidade.","E) Eficiência."], resposta_correta:0, explicacao:"Justificativa: Autotutela é o poder-dever da administração de controlar seus próprios atos (Súmula 473 do STF). Dica do Especialista: É um dos princípios 'implícitos' mais cobrados. Decore: Anular (ilegalidade) / Revogar (conveniência).", status:0, historico:0 },
{ id:299, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Sobre a relação entre ética e legalidade, assinale a afirmação correta:", imagem:null, alternativas:["A) Tudo o que é legal é necessariamente ético no âmbito administrativo.","B) A lei é o limite máximo da ética; além da lei, nada pode ser exigido do servidor.","C) Nem tudo o que é legal é ético, pois a ética exige conformidade com a justiça e a moralidade.","D) Em caso de conflito, a conveniência política deve prevalecer sobre a legalidade e a ética.","E) A ética administrativa aplica-se apenas aos cargos de chefia, não aos assistentes administrativos."], resposta_correta:2, explicacao:"Justificativa: A ética é mais ampla que a lei. Pode-se estar dentro da lei (literalidade) e ainda assim agir de forma imoral (intenção). Dica do Especialista: Use a lógica: Legalidade é o mínimo; Ética é o ideal.", status:0, historico:0 },
{ id:300, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"O princípio da moralidade administrativa exige que o agente público paute sua conduta por critérios de:", imagem:null, alternativas:["A) Amizade e compadrio com os colegas de setor.","B) Lealdade às instituições e boa-fé no exercício das funções.","C) Sigilo absoluto sobre todos os gastos da autarquia.","D) Preferência por empresas de conhecidos em processos de compra.","E) Obediência cega a ordens ilegais de superiores hierárquicos."], resposta_correta:1, explicacao:"Justificativa: Boa-fé e lealdade são pilares da moralidade administrativa. Dica do Especialista: Moralidade na Quadrix = Boa-fé + Honestidade + Lealdade.", status:0, historico:0 },
{ id:301, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Um servidor público que utiliza papel e impressora do CRECI para imprimir materiais de estudo pessoais para outros concursos está:", imagem:null, alternativas:["A) Agindo com eficiência, pois está aproveitando o tempo livre para estudar.","B) Praticando um ato ético de autoaperfeiçoamento profissional.","C) Violando o princípio da moralidade ao utilizar recursos públicos para fins privados.","D) Isento de qualquer crítica, desde que não atrapalhe suas tarefas diárias.","E) Agindo dentro da legalidade, pois não há lei que proíba especificamente o uso de papel."], resposta_correta:2, explicacao:"Justificativa: Recursos públicos são destinados exclusivamente ao interesse público. Uso privado é imoral e ilegal. Dica do Especialista: Bens da repartição para uso pessoal = Improbidade + Infração Ética.", status:0, historico:0 },
{ id:302, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"O princípio que estabelece que o interesse da coletividade deve prevalecer sobre o interesse de indivíduos isolados é o da:", imagem:null, alternativas:["A) Indisponibilidade do interesse público.","B) Supremacia do interesse público sobre o privado.","C) Legalidade estrita.","D) Publicidade administrativa.","E) Presunção de legitimidade."], resposta_correta:1, explicacao:"Justificativa: É o princípio basilar do Direito Administrativo que justifica as prerrogativas estatais. Dica do Especialista: A 'Supremacia' é a base dos poderes; a 'Indisponibilidade' é a base dos deveres.", status:0, historico:0 },
{ id:303, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Analise: 'A função pública deve ser tida como exercício de cidadania e, consequentemente, como encargo de alta responsabilidade'. Essa visão implica que:", imagem:null, alternativas:["A) O servidor pode cobrar taxas extras por fora para garantir a rapidez do serviço.","B) O descaso com o patrimônio público é uma falta meramente administrativa, sem teor ético.","C) A dignidade da pessoa humana deve ser respeitada em todos os atendimentos do conselho.","D) O servidor é um cidadão comum e não precisa prestar contas de seus atos à sociedade.","E) O cargo público é uma propriedade do servidor, que dele pode dispor como desejar."], resposta_correta:2, explicacao:"Justificativa: A ética pública está ancorada no respeito ao cidadão e na responsabilidade social. Dica do Especialista: A Quadrix sempre coloca alternativas que tentam 'diminuir' a responsabilidade do servidor; descarte-as imediatamente.", status:0, historico:0 },
{ id:304, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"De acordo com as recentes alterações na Lei nº 8.429/1992, assinale a alternativa que descreve corretamente o elemento subjetivo necessário para a configuração do ato de improbidade administrativa:", imagem:null, alternativas:["A) Admite-se a modalidade culposa apenas nos atos que geram prejuízo ao erário.","B) O dolo deve ser genérico, bastando a vontade livre de realizar a conduta descrita no tipo.","C) Exige-se o dolo específico, caracterizado pela vontade livre e consciente de alcançar o resultado ilícito.","D) A culpa grave equipara-se ao dolo para fins de perda da função pública e suspensão de direitos.","E) O mero exercício da função ou desempenho de competência pública, sem prova de má-fé, presume o dolo."], resposta_correta:2, explicacao:"Justificativa: Com a Lei 14.230/21, a improbidade culposa foi extinta e exige-se dolo específico (vontade de alcançar o resultado ilícito).", status:0, historico:0 },
{ id:305, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Um assistente administrativo do CRECI-BA, visando beneficiar um amigo, facilita a aquisição de um bem por preço inferior ao de mercado. Essa conduta, segundo a Lei nº 8.429/1992, tipifica-se como:", imagem:null, alternativas:["A) Ato que atenta contra os princípios da administração pública, exclusivamente.","B) Ato de improbidade que importa enriquecimento ilícito do próprio servidor.","C) Ato de improbidade administrativa que causa prejuízo ao erário.","D) Mera irregularidade administrativa, não passível de punição por improbidade se não houver propina.","E) Ato de improbidade por omissão, visto que ele deixou de fiscalizar o valor correto."], resposta_correta:2, explicacao:"Justificativa: Facilitar a aquisição por preço inferior causa dano patrimonial efetivo (Art. 10).", status:0, historico:0 },
{ id:306, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Sobre as sanções previstas para atos que atentam contra os princípios da administração pública, assinale a alternativa correta em conformidade com a redação atual da lei:", imagem:null, alternativas:["A) É cabível a suspensão de direitos políticos por até 12 anos.","B) É cabível a perda da função pública, independentemente do tempo de serviço.","C) É cabível o pagamento de multa civil de até 24 vezes o valor da remuneração percebida pelo agente.","D) O ressarcimento ao erário é dispensável, visto que não houve prejuízo financeiro direto.","E) A sanção de proibição de contratar com o Poder Público deve ser sempre de 10 anos."], resposta_correta:2, explicacao:"Justificativa: Para atos contra princípios (Art. 11), a multa é de até 24 vezes a remuneração. Não há mais suspensão de direitos políticos nem perda da função para o Art. 11.", status:0, historico:0 },
{ id:307, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Considere que um ex-dirigente do conselho tenha deixado o cargo há 9 anos. O Ministério Público decide ajuizar ação de improbidade hoje por atos cometidos no último dia de mandato. Sobre a prescrição, é correto afirmar:", imagem:null, alternativas:["A) A ação é imprescritível, pois trata-se de defesa do patrimônio público.","B) A ação prescreveu, pois o prazo prescricional unificado é de 8 anos a contar da ocorrência do fato.","C) O prazo prescricional é de 5 anos, seguindo a regra geral dos servidores federais.","D) A prescrição ocorre em 10 anos para casos de enriquecimento ilícito.","E) Não corre prescrição enquanto o agente não for formalmente notificado pelo Tribunal de Contas."], resposta_correta:1, explicacao:"Justificativa: A Lei 14.230 unificou o prazo em 8 anos contados da ocorrência do fato ou da cessação da permanência.", status:0, historico:0 },
{ id:308, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"A aplicação das sanções da Lei de Improbidade Administrativa independe:", imagem:null, alternativas:["A) Da ocorrência de dolo por parte do agente público.","B) Da efetiva ocorrência de dano ao patrimônio público, salvo quanto à pena de ressarcimento.","C) Da aprovação ou rejeição das contas pelo Tribunal de Contas competentes.","D) Da existência de cargo, emprego ou função pública na data da condenação.","E) Da demonstração de que o ato visava o benefício de terceiros."], resposta_correta:2, explicacao:"Justificativa: O Art. 21, II, diz que a aplicação independe da aprovação ou rejeição das contas.", status:0, historico:0 },
{ id:309, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Assinale a alternativa que apresenta uma conduta que NÃO MAIS constitui ato de improbidade que atenta contra os princípios da administração pública (Art. 11):", imagem:null, alternativas:["A) Revelar fato ou circunstância de que tem ciência em razão das atribuições e que deva permanecer em segredo.","B) Negar publicidade aos atos oficiais, salvo os casos de sigilo previstos em lei.","C) Frustrar a licitude de processo licitatório ou de processo seletivo para simplificado.","D) Deixar de prestar contas quando esteja obrigado a fazê-lo, desde que para ocultar irregularidades.","E) Praticar ato visando fim proibido em lei ou regulamento ou diverso daquele previsto na regra de competência."], resposta_correta:4, explicacao:"Justificativa: O inciso I do Art. 11 foi revogado. Atualmente, as condutas do Art. 11 são taxativas.", status:0, historico:0 },
{ id:310, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Em relação à responsabilidade de terceiros na Lei de Improbidade, assinale a opção correta:", imagem:null, alternativas:["A) O terceiro que não é agente público não pode ser processado com base na Lei nº 8.429/1992.","B) O terceiro responde apenas se houver dano material ao erário, excluindo-se enriquecimento ilícito.","C) As disposições da lei são aplicáveis ao terceiro que, mesmo não sendo agente público, induza ou concorra dolosamente para o ato.","D) A punição do terceiro independe da punição do agente público que praticou o ato principal.","E) O terceiro pessoa jurídica não pode ser responsabilizado, apenas seus sócios majoritários."], resposta_correta:2, explicacao:"Justificativa: Art. 3º: Terceiro responde se induzir ou concorrer dolosamente.", status:0, historico:0 },
{ id:311, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Sobre a sucessão hereditária na Lei de Improbidade, se o agente público falecer durante o processo:", imagem:null, alternativas:["A) O processo é extinto imediatamente, visto que as penas de improbidade são personalíssimas.","B) O sucessor responde por todas as penas, inclusive suspensão de direitos políticos.","C) O sucessor está sujeito às cominações de perda de bens e ressarcimento até o limite da herança.","D) A multa civil é perdoada, mas o ressarcimento deve ser pago integralmente pelos herdeiros.","E) A responsabilidade do sucessor limita-se aos casos de enriquecimento ilícito, excluindo prejuízo ao erário."], resposta_correta:2, explicacao:"Justificativa: Art. 8º: O sucessor está sujeito à obrigação de reparar o dano e à perda de bens até o limite do valor da herança.", status:0, historico:0 },
{ id:312, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Analise: 'O Ministério Público poderá celebrar acordo de não persecução cível'. Sobre esse instrumento, é correto afirmar:", imagem:null, alternativas:["A) É proibido em casos que envolvam enriquecimento ilícito acima de 100 salários mínimos.","B) Exige, entre outros requisitos, o integral ressarcimento do dano ao erário.","C) Pode ser celebrado apenas após o trânsito em julgado da sentença condenatória.","D) Dispensa a confissão do investigado para garantir a celeridade do processo.","E) É uma decisão unilateral do Juiz, não dependendo de proposta do Ministério Público."], resposta_correta:1, explicacao:"Justificativa: Art. 17-B: O ANPC exige o ressarcimento integral e a oitiva do ente lesado.", status:0, historico:0 },
{ id:313, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Dentre as penas abaixo, qual pode ser aplicada a um agente que praticou ato de improbidade que importa em enriquecimento ilícito, mas NÃO pode ser aplicada para atos contra princípios?", imagem:null, alternativas:["A) Multa civil.","B) Ressarcimento integral do dano.","C) Suspensão de direitos políticos.","D) Perda da função pública.","E) Proibição de contratar com o poder público."], resposta_correta:2, explicacao:"Justificativa: Atos contra princípios (Art. 11) não possuem mais as penas de suspensão de direitos políticos e perda da função pública.", status:0, historico:0 },
{ id:314, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Uma empresa de tecnologia que se beneficia dolosamente de um edital viciado no CRECI-BA pode ser processada por improbidade administrativa. Contudo, se a conduta também for tipificada na Lei Anticorrupção (Lei nº 12.846/2013):", imagem:null, alternativas:["A) A empresa deve responder apenas pela Lei de Improbidade por ser lei especial.","B) A empresa responderá obrigatoriamente em ambos os processos de forma independente.","C) A pessoa jurídica não sofrerá as sanções da Lei de Improbidade se o ato já for punido pela Lei Anticorrupção.","D) O processo de improbidade absorve todas as multas da Lei Anticorrupção.","E) A Lei Anticorrupção é inconstitucional para autarquias profissionais como o CRECI."], resposta_correta:2, explicacao:"Justificativa: Art. 3º, § 2º: Se o ato for punido pela Lei 12.846, a PJ não sofre sanções da LIA.", status:0, historico:0 },
{ id:315, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Assinale a alternativa que indica o prazo máximo de suspensão de direitos políticos para o ato de improbidade que causa prejuízo ao erário:", imagem:null, alternativas:["A) Até 8 anos.","B) Até 10 anos.","C) Até 12 anos.","D) Até 14 anos.","E) A lei não prevê mais suspensão para prejuízo ao erário."], resposta_correta:2, explicacao:"Justificativa: Prejuízo ao erário (Art. 10): suspensão de até 12 anos. Enriquecimento ilícito (Art. 9): até 14 anos.", status:0, historico:0 },
{ id:316, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Considere: I. 'Divergência interpretativa da lei baseada em jurisprudência não pacificada'. II. 'Vontade de omitir informação para esconder erro técnico'. Qual(is) item(ns) configura(m) improbidade?", imagem:null, alternativas:["A) Apenas I.","B) Apenas II.","C) I e II.","D) Nenhum dos dois, pois erro técnico é culpa.","E) Ambos, pois a administração pública exige perfeição."], resposta_correta:1, explicacao:"Justificativa: Art. 1º, § 8º: Divergência interpretativa não é improbidade. A II indica má-fé (dolo), logo é improbidade.", status:0, historico:0 },
{ id:317, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Sobre a indisponibilidade de bens em ações de improbidade, é INCORRETO afirmar:", imagem:null, alternativas:["A) Pode recair sobre bens adquiridos antes do ato ilícito.","B) Exige a demonstração de perigo de dano ou risco ao resultado útil do processo.","C) Pode atingir valores em conta corrente até o limite de 40 salários mínimos, sem exceções.","D) Deve recair prioritariamente sobre veículos e imóveis.","E) Não pode ser decretada se o dano ao erário for meramente estimado, sem liquidez."], resposta_correta:2, explicacao:"Justificativa: Art. 16, § 10: Valores até 40 salários mínimos em poupança ou outras aplicações são impenhoráveis.", status:0, historico:0 },
{ id:318, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"A ação para a aplicação das sanções de que trata a Lei nº 8.429/1992 será proposta pelo:", imagem:null, alternativas:["A) Ministério Público ou pela Pessoa Jurídica interessada.","B) Exclusivamente pelo Ministério Público.","C) Qualquer cidadão no gozo de seus direitos políticos.","D) Conselho Federal (COFECI) em caso de autarquias regionais.","E) Juiz de Direito da Comarca onde ocorreu o fato."], resposta_correta:1, explicacao:"Justificativa: Art. 17: A legitimidade ativa passou a ser EXCLUSIVA do Ministério Público.", status:0, historico:0 },
{ id:319, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Qual conduta abaixo constitui enriquecimento ilícito (Art. 9) e gera a pena de perda dos bens acrescidos ao patrimônio?", imagem:null, alternativas:["A) Doar bens da autarquia para entidade privada sem licitação.","B) Adquirir bens de valor desproporcional à evolução do patrimônio sem justificativa.","C) Retardar ou deixar de praticar ato de ofício indevidamente.","D) Frustrar a licitude de concurso público para favorecer parente.","E) Ordenar despesa não autorizada em lei ou regulamento."], resposta_correta:1, explicacao:"Justificativa: A desproporcionalidade patrimonial injustificada (Art. 9, VII) é presunção de enriquecimento ilícito.", status:0, historico:0 },
{ id:320, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Se o réu em ação de improbidade for condenado a ressarcir o erário, mas também for condenado em processo administrativo disciplinar (PAD) a devolver o mesmo valor:", imagem:null, alternativas:["A) Ele deverá pagar as duas vezes como medida pedagógica.","B) O valor pago no PAD deve ser abatido do montante da condenação judicial.","C) A condenação judicial anula automaticamente a decisão administrativa.","D) O ressarcimento judicial tem prioridade sobre o ressarcimento administrativo.","E) A lei proíbe que se cobre ressarcimento em duas instâncias diferentes."], resposta_correta:1, explicacao:"Justificativa: Art. 21, § 4º: Ressarcimento em uma instância deve ser compensado na outra para evitar enriquecimento do Estado.", status:0, historico:0 },
{ id:321, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Sobre a perda da função pública como sanção de improbidade, assinale a correta:", imagem:null, alternativas:["A) Atinge apenas o cargo que o agente ocupava no momento do ato.","B) Atinge, em regra, todos os vínculos que o agente possua com o poder público na data da decisão.","C) Só pode ser decretada pelo Juiz se houver reincidência específica em 5 anos.","D) É automática após o recebimento da petição inicial pelo magistrado.","E) Aplica-se apenas a cargos eletivos e de confiança, não a servidores de carreira."], resposta_correta:1, explicacao:"Justificativa: Art. 12, § 1º: A perda da função atinge o vínculo atual, mas o juiz pode estender a outros vínculos em casos graves.", status:0, historico:0 },
{ id:322, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Um estagiário do CRECI-BA, que não recebe remuneração, utiliza um veículo oficial para fins particulares com o consentimento doloso de seu supervisor. Neste caso:", imagem:null, alternativas:["A) O estagiário não responde por improbidade, pois não é agente público remunerado.","B) Apenas o supervisor responde, pois o estagiário não possui vínculo estatutário.","C) Ambos podem responder por improbidade, pois o conceito de agente público abrange quem atua sem remuneração e transitoriamente.","D) O ato é considerado mera falta disciplinar por envolver estagiário.","E) A lei de improbidade não se aplica a autarquias de fiscalização profissional."], resposta_correta:2, explicacao:"Justificativa: Art. 2º: O conceito de agente público é o mais amplo possível (com ou sem remuneração).", status:0, historico:0 },
{ id:323, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"A multa civil pode ser aumentada até o dobro, se o juiz considerar que, em virtude da situação econômica do réu, o valor inicial é:", imagem:null, alternativas:["A) Incompatível com o dano causado.","B) Insuficiente para a finalidade de punição e dissuasão.","C) Inferior ao valor da remuneração do agente no ano do fato.","D) Contrário ao princípio da dignidade da pessoa humana.","E) Maior que o lucro obtido pelo agente com o ato ilícito."], resposta_correta:1, explicacao:"Justificativa: Art. 12, § 2º: Se o réu for muito rico e a multa padrão for 'irrisória', o juiz pode dobrar o valor.", status:0, historico:0 },
{ id:324, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Nos termos da Lei nº 9.784/1999, que regula o processo administrativo federal, é direito do administrado perante a Administração Pública:", imagem:null, alternativas:["A) Ser tratado com urbanidade, apenas se for servidor de outro órgão.","B) Fazer-se assistir, obrigatoriamente, por advogado em todas as fases do processo.","C) Ter ciência da tramitação dos processos em que tenha a condição de interessado e obter cópias de documentos.","D) Prestar depoimento apenas se houver ordem judicial prévia.","E) Escolher o servidor que irá analisar seu processo por afinidade técnica."], resposta_correta:2, explicacao:"Justificativa: Art. 3º, II: Direito à informação e cópias. Advogado é opcional no PA.", status:0, historico:0 },
{ id:325, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Dentre os princípios expressamente previstos no caput do Art. 2º da Lei nº 9.784/1999, NÃO se inclui o da:", imagem:null, alternativas:["A) Motivação.","B) Razoabilidade.","C) Segurança Jurídica.","D) Ampla Defesa.","E) Supremacia do Poder Hierárquico."], resposta_correta:4, explicacao:"Justificativa: Hierarquia é critério de organização, não princípio do caput da Lei 9784.", status:0, historico:0 },
{ id:326, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Sobre a competência no processo administrativo, assinale a alternativa correta:", imagem:null, alternativas:["A) A competência é irrenunciável e se exerce pelos órgãos administrativos a que foi atribuída como própria.","B) Um órgão administrativo não pode delegar parte de sua competência a outros órgãos se não houver subordinação hierárquica.","C) O ato de delegação e sua revogação não precisam ser publicados no meio oficial.","D) A avocação de competência é a regra, ocorrendo sempre que o superior desejar.","E) É delegável a decisão de recursos administrativos para garantir celeridade."], resposta_correta:0, explicacao:"Justificativa: Art. 11: Competência é irrenunciável. Delegação pode ocorrer mesmo sem hierarquia (Art. 12).", status:0, historico:0 },
{ id:327, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Um servidor do CRECI-BA é designado para julgar um processo onde o interessado é seu primo de 2º grau. Segundo a Lei nº 9.784/1999, esse servidor:", imagem:null, alternativas:["A) Está impedido de atuar, pois há relação de parentesco.","B) É apenas suspeito, podendo atuar se declarar sua imparcialidade.","C) Pode atuar normalmente, visto que o impedimento é apenas para parentes de 1º grau.","D) Deve solicitar autorização ao Ministério Público para prosseguir.","E) Está impedido apenas se o primo for credor ou devedor do servidor."], resposta_correta:0, explicacao:"Justificativa: Art. 18, II: Impedimento por parentesco até o 3º grau.", status:0, historico:0 },
{ id:328, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"A Administração Pública Federal tem o dever de emitir decisão explícita em processos administrativos. Concluída a instrução, o prazo para decidir é de:", imagem:null, alternativas:["A) 15 dias, improrrogáveis.","B) 30 dias, podendo ser prorrogado por igual período mediante motivação.","C) 60 dias, se o processo envolver matéria técnica complexa.","D) 5 dias, sob pena de nulidade do ato por omissão.","E) Não há prazo legal, devendo observar-se o tempo razoável."], resposta_correta:1, explicacao:"Justificativa: Art. 49: Prazo de 30 dias, prorrogável por mais 30.", status:0, historico:0 },
{ id:329, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"No processo administrativo, os atos do órgão instrucional que não tenham por objeto a decisão de mérito deverão ser praticados no prazo de:", imagem:null, alternativas:["A) 2 dias.","B) 5 dias.","C) 10 dias.","D) 15 dias.","E) 30 dias."], resposta_correta:1, explicacao:"Justificativa: Art. 24: Prazo de 5 dias para atos gerais, salvo disposição em contrário.", status:0, historico:0 },
{ id:330, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Considera-se 'interessado' no processo administrativo, para fins de direito a recurso:", imagem:null, alternativas:["A) Exclusivamente a pessoa física que iniciou o processo.","B) Aqueles que, sem terem iniciado o processo, têm direitos ou interesses que possam ser afetados pela decisão.","C) Apenas o Ministério Público e a Defensoria Pública.","D) Servidores do órgão que tenham amizade com o requerente.","E) Qualquer cidadão, independentemente de sofrer impacto com a decisão."], resposta_correta:1, explicacao:"Justificativa: Art. 9º, II: Interessados são os que têm direitos afetados.", status:0, historico:0 },
{ id:331, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Sobre a motivação dos atos administrativos na Lei nº 9.784/1999, assinale a INCORRETA:", imagem:null, alternativas:["A) Devem ser motivados os atos que neguem, limitem ou afetem direitos ou interesses.","B) A motivação deve ser clara e congruente, podendo consistir em declaração de concordância com fundamentos de pareceres anteriores.","C) A motivação é facultativa em atos que decidam recursos administrativos.","D) Devem ser motivados os atos que dispensem ou declarem a inexigibilidade de processo licitatório.","E) A motivação deve indicar os fundamentos de fato e de direito."], resposta_correta:2, explicacao:"Justificativa: Art. 50, VII: A decisão de recursos administrativos DEVE ser motivada.", status:0, historico:0 },
{ id:332, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Os prazos no processo administrativo federal começam a correr a partir da data da cientificação oficial e são contados:", imagem:null, alternativas:["A) Em dias úteis, excluindo o dia do começo e incluindo o do vencimento.","B) Em dias corridos, incluindo o dia do começo e excluindo o do vencimento.","C) Em dias corridos, excluindo o dia do começo e incluindo o do vencimento.","D) Em horas úteis, a partir do protocolo.","E) Conforme o critério do servidor responsável pela intimação."], resposta_correta:2, explicacao:"Justificativa: Art. 66: Dias corridos, exclui o início e inclui o fim.", status:0, historico:0 },
{ id:333, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Das decisões administrativas cabe recurso, em face de razões de legalidade e de mérito. O prazo para interposição de recurso administrativo é de:", imagem:null, alternativas:["A) 5 dias úteis.","B) 10 dias corridos.","C) 15 dias corridos.","D) 30 dias úteis.","E) 60 dias corridos."], resposta_correta:1, explicacao:"Justificativa: Art. 59: Prazo de 10 dias para recorrer.", status:0, historico:0 },
{ id:334, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Em um processo no CRECI-BA, a autoridade nota que houve um vício de legalidade insanável. Ela deve:", imagem:null, alternativas:["A) Revogar o ato por razões de interesse público.","B) Anular o ato, de ofício ou mediante provocação.","C) Convalidar o ato, pois o tempo cura a ilegalidade.","D) Suspender o processo até que o interessado conserte o vício.","E) Encaminhar o caso para a Polícia Federal imediatamente."], resposta_correta:1, explicacao:"Justificativa: Art. 53: A Administração DEVE anular atos ilegais.", status:0, historico:0 },
{ id:335, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Salvo disposição legal específica, o recurso administrativo tramitará, no máximo, por:", imagem:null, alternativas:["A) Duas instâncias administrativas.","B) Três instâncias administrativas.","C) Quatro instâncias administrativas.","D) Instâncias ilimitadas até o esgotamento da matéria.","E) Uma única instância, sendo a decisão soberana."], resposta_correta:1, explicacao:"Justificativa: Art. 57: Máximo de 3 instâncias.", status:0, historico:0 },
{ id:336, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Sobre a desistência e renúncia no processo administrativo, assinale a correta:", imagem:null, alternativas:["A) O interessado pode desistir do pedido, mas isso impede que ele entre com novo pedido no futuro.","B) A desistência do interessado obriga a Administração a extinguir o processo imediatamente.","C) A Administração pode prosseguir com o processo se considerar que o interesse público assim o exige, mesmo com desistência.","D) Desistência e renúncia são atos que exigem concordância do Ministério Público.","E) Só é permitida a desistência se o processo não tiver ultrapassado a fase de instrução."], resposta_correta:2, explicacao:"Justificativa: Art. 51, § 2º: A Administração pode seguir se houver interesse público.", status:0, historico:0 },
{ id:337, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"A intimação do interessado para ciência de decisão ou efetivação de diligência deve observar a antecedência mínima de:", imagem:null, alternativas:["A) 24 horas.","B) 48 horas.","C) 3 dias úteis.","D) 5 dias corridos.","E) 15 dias corridos."], resposta_correta:2, explicacao:"Justificativa: Art. 26, § 2º: Antecedência mínima de 3 dias úteis.", status:0, historico:0 },
{ id:338, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Quando o vício de um ato administrativo for sanável e não acarretar lesão ao interesse público nem prejuízo a terceiros, a autoridade poderá:", imagem:null, alternativas:["A) Anulá-lo preventivamente.","B) Revogá-lo por conveniência.","C) Convalidá-lo.","D) Ignorá-lo sob o manto da discricionariedade.","E) Extingui-lo por caducidade."], resposta_correta:2, explicacao:"Justificativa: Art. 55: Convalidação de vícios sanáveis.", status:0, historico:0 },
{ id:339, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Inexistindo disposição específica, os atos do órgão instrucional deverão ser praticados no prazo de cinco dias. Caso não seja cumprido pelo servidor:", imagem:null, alternativas:["A) O ato é nulo de pleno direito.","B) O processo é arquivado por inércia.","C) O superior deve ser informado para fins de apuração de responsabilidade.","D) O prazo é dobrado automaticamente sem necessidade de aviso.","E) O interessado ganha o direito de decidir a matéria em seu favor."], resposta_correta:2, explicacao:"Justificativa: Art. 24, § 1º: O descumprimento de prazo deve ser reportado ao superior.", status:0, historico:0 },
{ id:340, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Assinale a alternativa que indica uma hipótese em que o processo administrativo NÃO pode ser iniciado:", imagem:null, alternativas:["A) Por iniciativa de associações em defesa de direitos coletivos.","B) Por provocação de interessado pessoa jurídica.","C) De ofício pela autoridade que detém a competência.","D) Anonimamente, em qualquer circunstância, sem indicação de fatos.","E) Por menores de 18 anos que possuam capacidade civil nos termos da lei."], resposta_correta:3, explicacao:"Justificativa: O PA exige identificação do interessado (Art. 6º).", status:0, historico:0 },
{ id:341, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Um processo administrativo federal pode ser extinto quando o objeto da decisão se tornar impossível, inútil ou prejudicado por fato superveniente. Esse encerramento deve ser:", imagem:null, alternativas:["A) Mantido em sigilo para evitar recursos.","B) Decidido por sorteio entre os conselheiros.","C) Motivadoramente declarado pela autoridade.","D) Comunicado apenas ao Ministério Público.","E) Realizado sem necessidade de intimação do interessado."], resposta_correta:2, explicacao:"Justificativa: Art. 52: Extinção por perda de objeto exige motivação.", status:0, historico:0 },
{ id:342, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Sobre a fase de instrução no processo administrativo, é correto afirmar que:", imagem:null, alternativas:["A) Cabe ao interessado a prova dos fatos que tenha alegado, mas a Administração pode produzir provas de ofício.","B) É vedada a realização de audiências públicas para não expor a intimidade do administrado.","C) O interessado não tem direito de formular quesitos em perícias técnicas.","D) Elementos de prova obtidos por meios ilícitos são aceitos se ajudarem na busca pela verdade real.","E) A Administração não pode recusar provas propostas pelos interessados em nenhuma hipótese."], resposta_correta:0, explicacao:"Justificativa: Art. 28 e 29: Ônus da prova é do interessado, mas há o impulso oficial.", status:0, historico:0 },
{ id:343, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"O direito da Administração de anular os atos administrativos de que decorram efeitos favoráveis para os destinatários decai em:", imagem:null, alternativas:["A) 2 anos.","B) 5 anos, salvo comprovada má-fé.","C) 8 anos, seguindo o prazo de improbidade.","D) 10 anos, para atos que envolvam gastos financeiros.","E) Nunca, pois a nulidade é absoluta."], resposta_correta:1, explicacao:"Justificativa: Art. 54: Prazo decadencial de 5 anos (salvo má-fé).", status:0, historico:0 },
{ id:344, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"No que se refere à transparência ativa prevista na Lei nº 12.527/2011, é dever dos órgãos e entidades públicas a divulgação em seus sítios oficiais de informações de interesse coletivo, EXCETO:", imagem:null, alternativas:["A) Estrutura organizacional e competências do órgão.","B) Registros de quaisquer repasses ou transferências de recursos financeiros.","C) Informações detalhadas sobre a vida privada de seus dirigentes.","D) Procedimentos para a realização de licitações e seus respectivos editais.","E) Respostas a perguntas mais frequentes da sociedade."], resposta_correta:2, explicacao:"Justificativa: A LAI protege a vida privada, honra e imagem (Art. 31). A transparência ativa foca em dados institucionais e financeiros do órgão.", status:0, historico:0 },
{ id:345, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"De acordo com a Lei nº 13.709/2018 (LGPD), o dado pessoal sobre origem racial ou étnica, convicção religiosa, opinião política, filiação a sindicato ou a organização de caráter religioso, filosófico ou político é classificado como:", imagem:null, alternativas:["A) Dado pessoal anonimizado.","B) Dado pessoal sensível.","C) Dado público de livre acesso.","D) Dado institucional irrestrito.","E) Dado pessoal de natureza administrativa."], resposta_correta:1, explicacao:"Justificativa: Art. 5º, II: Define dados sensíveis como aqueles que podem gerar discriminação (origem, religião, política, etc.).", status:0, historico:0 },
{ id:346, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Ao receber um pedido de acesso à informação, caso a informação não esteja disponível de imediato, o órgão deverá responder no prazo de até:", imagem:null, alternativas:["A) 10 dias, improrrogáveis.","B) 15 dias, podendo ser prorrogado por mais 5 dias.","C) 20 dias, podendo ser prorrogado por mais 10 dias, mediante justificativa.","D) 30 dias, independentemente de justificativa.","E) 5 dias úteis, contados do recebimento."], resposta_correta:2, explicacao:"Justificativa: Art. 11, § 1º: Prazo de 20 dias, prorrogável por mais 10 dias com justificativa expressa.", status:0, historico:0 },
{ id:347, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Um Conselho Regional de Corretores de Imóveis (CRECI) contrata uma empresa de software para realizar o processamento dos dados de seus inscritos. Sob a ótica da LGPD, o CRECI e a empresa de software são, respectivamente:", imagem:null, alternativas:["A) Operador e Controlador.","B) Titular e Encarregado.","C) Controlador e Operador.","D) Agente de Tratamento e Autoridade Nacional.","E) Usuário e Processador."], resposta_correta:2, explicacao:"Justificativa: Art. 5º, VI e VII: O Controlador (CRECI) toma as decisões; o Operador (empresa) realiza o tratamento em nome do controlador.", status:0, historico:0 },
{ id:348, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"As informações que possam colocar em risco a segurança do Presidente e Vice-Presidente da República e respectivos cônjuges e filhos serão classificadas como reservadas e ficarão sob sigilo até o término do mandato, EXCETO:", imagem:null, alternativas:["A) Se envolverem gastos com cartão corporativo.","B) Se o Presidente decidir pela publicidade imediata.","C) Se o mandato for interrompido por renúncia.","D) Se houver decisão do Poder Judiciário em sentido contrário.","E) A lei não prevê exceções, o sigilo é absoluto por 100 anos."], resposta_correta:1, explicacao:"Justificativa: Art. 24, § 2º: O sigilo dura até o término do mandato ou período presidencial, mas não há essa exceção de 'gasto' ou 'renúncia' na letra da lei.", status:0, historico:0 },
{ id:349, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"O princípio da LGPD que garante aos titulares a consulta facilitada e gratuita sobre a forma e a duração do tratamento, bem como sobre a integralidade de seus dados pessoais, é o da:", imagem:null, alternativas:["A) Prevenção.","B) Transparência.","C) Livre acesso.","D) Necessidade.","E) Não discriminação."], resposta_correta:2, explicacao:"Justificativa: Art. 6º, IV: O livre acesso garante ao titular saber como seus dados são tratados de forma gratuita.", status:0, historico:0 },
{ id:350, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"No processo de classificação de informação em grau de sigilo, a autoridade que possui competência para classificar uma informação como ULTRASSECRETA no âmbito federal é:", imagem:null, alternativas:["A) Qualquer servidor ocupante de cargo DAS-4 ou superior.","B) Comandantes da Marinha, Exército e Aeronáutica.","C) O Encarregado de Dados do órgão.","D) O Presidente do Conselho Regional interessado.","E) Apenas o Presidente da República."], resposta_correta:1, explicacao:"Justificativa: Art. 27, I: Chefes de missões diplomáticas e comandantes militares podem classificar como ultrassecreta.", status:0, historico:0 },
{ id:351, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"A pessoa indicada pelo controlador e operador para atuar como canal de comunicação entre o controlador, os titulares dos dados e a Autoridade Nacional de Proteção de Dados (ANPD) é o:", imagem:null, alternativas:["A) Auditor Independente.","B) Ouvidor-Geral.","C) Encarregado.","D) Gestor de Segurança da Informação.","E) Secretário de Transparência."], resposta_correta:2, explicacao:"Justificativa: Art. 5º, VIII: O Encarregado (DPO) é a ponte entre as partes envolvidas no tratamento.", status:0, historico:0 },
{ id:352, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"A Lei de Acesso à Informação estabelece que o serviço de busca e fornecimento da informação é gratuito, ressalvada a cobrança de:", imagem:null, alternativas:["A) Taxas de protocolo administrativo.","B) Honorários de pesquisa por hora trabalhada pelo servidor.","C) Valor correspondente ao custo dos serviços e materiais utilizados na reprodução de documentos.","D) Tarifas de conveniência para atendimento presencial.","E) Multas por pedidos considerados repetitivos."], resposta_correta:2, explicacao:"Justificativa: Art. 12: O acesso é gratuito, mas o material de reprodução (xerox, pendrive) pode ser cobrado.", status:0, historico:0 },
{ id:353, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Sobre o consentimento para tratamento de dados pessoais na LGPD, assinale a alternativa correta:", imagem:null, alternativas:["A) O consentimento deve ser sempre por escrito, sob pena de nulidade.","B) Pode ser revogado a qualquer momento mediante manifestação expressa do titular, por procedimento gratuito e facilitado.","C) O consentimento obtido para uma finalidade genérica é válido para todos os tratamentos futuros do órgão.","D) É proibido o tratamento de dados de crianças e adolescentes, mesmo com consentimento.","E) Uma vez dado o consentimento, o titular não pode mais solicitar a exclusão dos dados."], resposta_correta:1, explicacao:"Justificativa: Art. 8º, § 5º: O consentimento é revogável e a revogação deve ser fácil e gratuita.", status:0, historico:0 },
{ id:354, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Caso o acesso à informação seja negado, o requerente poderá interpor recurso contra a decisão no prazo de 10 dias a contar da sua ciência. Esse recurso deverá ser dirigido à:", imagem:null, alternativas:["A) Autoridade máxima do próprio órgão.","B) Autoridade hierarquicamente superior à que exarou a decisão negativa.","C) Controladoria-Geral da União, obrigatoriamente em primeira instância.","D) Justiça Federal, mediante petição assinada por advogado.","E) Comissão Mista de Reavaliação de Informações."], resposta_correta:1, explicacao:"Justificativa: Art. 15: O recurso administrativo sobe para a autoridade superior à que negou o pedido.", status:0, historico:0 },
{ id:355, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"A LGPD NÃO se aplica ao tratamento de dados pessoais realizado:", imagem:null, alternativas:["A) Por pessoa jurídica de direito público para fins de segurança pública.","B) Para fins exclusivamente jornalísticos e artísticos.","C) Por conselhos profissionais para fiscalização de seus inscritos.","D) Através de meios digitais por empresas de e-commerce nacionais.","E) Por profissionais liberais que mantêm cadastro de clientes."], resposta_correta:1, explicacao:"Justificativa: Art. 4º, II, 'a': A LGPD não se aplica para fins exclusivamente jornalísticos e artísticos.", status:0, historico:0 },
{ id:356, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Informações pessoais relativas à intimidade, vida privada, honra e imagem terão seu acesso restrito, independentemente de classificação de sigilo, pelo prazo máximo de:", imagem:null, alternativas:["A) 10 anos a contar da data de sua produção.","B) 30 anos a contar da data de sua produção.","C) 50 anos a contar da data de sua produção.","D) 100 anos a contar da data de sua produção.","E) Período indeterminado, enquanto o titular estiver vivo."], resposta_correta:3, explicacao:"Justificativa: Art. 31, § 1º, I: O prazo de proteção de dados pessoais na LAI é de 100 anos.", status:0, historico:0 },
{ id:357, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"A utilização de meios técnicos razoáveis e disponíveis no momento do tratamento, por meio dos quais um dado perde a possibilidade de associação, direta ou indireta, a um indivíduo, é chamada de:", imagem:null, alternativas:["A) Criptografia simétrica.","B) Pseudoanonimização.","C) Anonimização.","D) Eliminação de dados.","E) Blindagem digital."], resposta_correta:2, explicacao:"Justificativa: Art. 5º, XI: Definição de anonimização (perda de associação com o indivíduo).", status:0, historico:0 },
{ id:358, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Um cidadão solicita ao CRECI-BA uma listagem contendo o nome e o número de registro de todos os corretores ativos na região. Segundo a LAI, tal pedido:", imagem:null, alternativas:["A) Deve ser negado por violar a privacidade dos corretores.","B) Deve ser atendido, pois se trata de informação de interesse público e registro profissional.","C) Só pode ser atendido se houver autorização expressa de cada corretor.","D) Deve ser atendido mediante pagamento de uma taxa de serviço extraordinário.","E) Deve ser negado se o solicitante não apresentar o motivo da consulta."], resposta_correta:1, explicacao:"Justificativa: Registros profissionais e nomes de inscritos em autarquias são dados públicos por natureza da atividade.", status:0, historico:0 },
{ id:359, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"O tratamento de dados pessoais pode ser realizado sem o consentimento do titular em diversas hipóteses legais. NÃO constitui uma dessas hipóteses:", imagem:null, alternativas:["A) Para o cumprimento de obrigação legal ou regulatória pelo controlador.","B) Para a execução de políticas públicas previstas em leis e regulamentos.","C) Para a realização de pesquisas por órgão de pesquisa, garantida a anonimização sempre que possível.","D) Para fins de marketing direto e prospecção de clientes por empresas privadas.","E) Para a proteção da vida ou da incolumidade física do titular ou de terceiro."], resposta_correta:3, explicacao:"Justificativa: Marketing não é base legal automática; exige legítimo interesse ou consentimento, dependendo do caso.", status:0, historico:0 },
{ id:360, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Submetem-se aos ditames da Lei nº 12.527/2011 (LAI) as entidades privadas sem fins lucrativos que recebam, para realização de ações de interesse público, recursos públicos diretamente do orçamento ou mediante:", imagem:null, alternativas:["A) Empréstimos bancários com juros de mercado.","B) Contratos de gestão, termos de parceria ou convênios.","C) Doações de pessoas físicas anônimas.","D) Aluguéis de imóveis de terceiros.","E) Venda de produtos em bazares beneficentes."], resposta_correta:1, explicacao:"Justificativa: Art. 2º: Entidades privadas que recebem recursos via convênios/parcerias devem prestar contas via LAI.", status:0, historico:0 },
{ id:361, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"Conforme a LGPD, o tratamento de dados pessoais cujo acesso é público deve considerar a finalidade, a boa-fé e o interesse público que justificaram sua disponibilização. Nesse contexto:", imagem:null, alternativas:["A) Dados públicos podem ser utilizados para qualquer finalidade sem restrições.","B) É dispensada a observância dos princípios da LGPD por serem dados já expostos.","C) O controlador que obteve o dado público é dispensado de obter novo consentimento para finalidades idênticas.","D) O dado público torna-se propriedade de quem o coletou.","E) A lei proíbe o cruzamento de dados públicos com dados privados."], resposta_correta:2, explicacao:"Justificativa: Art. 7º, § 4º: Dispensa novo consentimento se a finalidade original for mantida.", status:0, historico:0 },
{ id:362, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"São consideradas informações que podem ser classificadas como sigilosas aquelas cuja divulgação possa, entre outros:", imagem:null, alternativas:["A) Revelar falhas de gestão de governantes eleitos.","B) Prejudicar ou causar risco a planos ou operações estratégicos das Forças Armadas.","C) Gerar críticas negativas na imprensa sobre o desempenho de uma autarquia.","D) Expor salários de servidores ocupantes de cargos efetivos.","E) Divulgar agendas de reuniões de conselheiros de órgãos profissionais."], resposta_correta:1, explicacao:"Justificativa: Art. 23, IV: Segurança nacional e planos militares são passíveis de classificação.", status:0, historico:0 },
{ id:363, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", banca:"Quadrix", enunciado:"A documentação do controlador que contém a descrição dos processos de tratamento de dados pessoais que podem gerar riscos às liberdades civis e aos direitos fundamentais é o:", imagem:null, alternativas:["A) Plano Diretor de TI.","B) Relatório de Impacto à Proteção de Dados Pessoais (RIPD).","C) Manual de Conduta Ética Digital.","D) Termo de Uso e Política de Privacidade.","E) Inventário de Ativos de Rede."], resposta_correta:1, explicacao:"Justificativa: Art. 5º, XVII: O RIPD descreve os processos e riscos do tratamento de dados.", status:0, historico:0 },
]